using namespace std;



int64_t MOD = 998244353;



int64_t N_MAX = 3010;



int64_t dp[3010][3010];



//modの割り算

// a/bをa*modint(b,MOD) %MODに変換

long long modinv(long long a, long long m) {

  long long b = m, u = 1, v = 0;

  while (b) {

    long long t = a / b;

    a -= t * b; swap(a, b);

    u -= t * v; swap(u, v);

  }

  u %= m;

  if (u < 0) u += m;

  return u;

}



//繰り返し二乗法

int64_t powmod(int64_t x, int64_t n) { 

  int64_t ans = 1;

  while (n > 0) {

    if ((n & 1) == 1) {

      ans = ans * x;

      ans %= MOD;

    }

    x = x * x;//一周する度にx, x^2, x^4, x^8となる

    x %= MOD;

    n >>= 1; //桁をずらす n = n >> 1

  }

  return ans;

}



